<span class="line"><span style="color:#F8F8F2;">y1 </span><span style="color:#F92672;">=</span><span style="color:#F8F8F2;"> np.tanh(points) </span><span style="color:#F92672;">+</span><span style="color:#AE81FF;"> 0.5</span></span>
